import React, { useState } from "react";

export default function MessageForm({ onSend }) {
  const [text, setText] = useState("");
  const submit = (event) => {
    event.preventDefault();
    if (!text.trim()) return;
    onSend(text);
    setText("");
  };

  return (
    <form className="message-form" onSubmit={submit}>
      <input type="text" placeholder="Type your message here..." value={text} onChange={(event) => setText(event.target.value)} maxLength={1000} />
      <button className="primary-btn" type="submit">Send</button>
    </form>
  );
}
